  String param=request.getParameter("p");
  String apname=request.getParameter("a");
  if(apname==null || user==null || param==null || !user.ifApManager(apname)) return;

  JSONObject jo=null;
  try{jo=new JSONObject(param);}catch(Exception e){}
  if(jo==null) {
    
      out.write("<script>location='/");
      out.print(apname);
      out.write("';</script>");

    return;
  }

  JSONArray installIds=jo.optJSONArray("install");
  JSONArray inviteEmails=jo.optJSONArray("invites");
  boolean ifInstall=installIds.length()>0;


  //can only run this for empty accounts
  //this check is bug prone (ex. when adding new sheet to /ragic-setup has caused user not able to finish register setup
  //so this is removed for now
//  int activeSheetCount=Account.getInstance(apname).getActiveSheetCount();
//  int activeUserCount=Account.getInstance(apname).getActiveUserCount();
//  if(activeUserCount>1 || activeSheetCount>0){
//    out.println("This is not a new account: active sheets "+activeSheetCount+", active users:"+activeUserCount);
//    return;
//  }


  //check if auto upgrade needed
  boolean autoUpgrade=installIds.length()>=2;
  boolean profUpgrade=installIds.length()>=3;
  if(autoUpgrade){
    //decide version
    String edition=Account.LITE2;
    if(profUpgrade) edition=Account.PROF;

    //do upgrade
    AccountPaymentStatus aps= Account.getInstance(apname).getPaymentStatus(true);
    aps.startFreeTrial(edition);
  }

  //install templates
  List<String> installed=new ArrayList<>();
  for(int i=0;i<installIds.length();i++){
    String installId=installIds.getString(i);
    AppInstallation instApp= StoreAppCache.getInstance().getAppInstallation(Encoder.parseInt(installId, -1), bundle.getString("langv5"));
    if(instApp==null) continue;
    List<String> instUrl=AppManager.installApplication(apname, instApp, true);
    if(instUrl!=null) installed.addAll(instUrl);

    //reset cache
    Account.getInstance(apname).resetAppCache();

    //add test data
    AppProperty aprop=new AppProperty();
    aprop.loadProperties(new File("cust/def/app/"+apname+"/app.properties"));
    aprop.setScope(instApp.getApname());
    for(String path : instApp.getPathAll()){
      for(String sheetIndex:instApp.getSheets(path)){
        //only install if the sheet is listed in app.properties
        List<String> targetSheet=aprop.getKey(path + "/" + sheetIndex);
        String[] sec=targetSheet.get(targetSheet.size()-1).split("/");
        NUIForm form=AppManager.getFormPage(apname,"/"+sec[1],Encoder.parseInt(sec[2]));
        MessageFacade.copyEntry(instApp.getApname(), path, Encoder.parseInt(sheetIndex, Const.NONODE), form, bundle, user, 1000);
      }
    }
    try{
      IntegrationManager.getInstance(apname).executeImport();
    }
    catch(Exception e){}

    //record installation
    SimpleDateFormat sdf=new SimpleDateFormat("yyyy/MM/dd HH:mm");
    new Log("install.log").log(sdf.format(new Date()) + "," + instApp.getApplicationName() + "," + instApp.getInstallTab() + "," + apname + "," + instApp.getAppId(), Log.INFO);
  }

  //add users
  APIQuery aq=new APIQuery(apname,"/ragic-setup",1);
  aq.setUpdateMode();
  for(int i=0;i<inviteEmails.length();i++){
    String email=inviteEmails.getString(i);
    if(Encoder.ifEmailValid(email)){
      APIEntry e=aq.insertAPIEntry();
      e.setFieldValue(DConst.USER_USERID_EMAIL,email);
      e.setFieldValue(DConst.USER_NAME,email);
      e.setFieldValue(DConst.USER_GROUP, Const.G_USER);
      e.setFieldValue(DConst.USER_STATUS, Const.USER_STATUS_NORMAL);
      e.setFieldValue(DConst.USER_EXTERNAL_TYPE, Const.USER_INTERNAL);
      //avoid concurrency and locking
      e.setIfQueue(false);
      e.setIfAsyncSavePostProcess(false);
      e.save(user,bundle);
    }
  }

  //record a register date, used to determine if a new on-boarding feature should be applied
  SimpleDateFormat sdf=new SimpleDateFormat("yyyyMMdd");
  user.saveSharedProperties("regdate",sdf.format(new Date()));


  // if no templates, create a default tab and a default sheet for user
  String generatedPath = "";
  if(!ifInstall){
      String newTabName = bundle.getString("autoCreatedTab");
      generatedPath = "/"+Encoder.makeUrl(newTabName);
      
      ArrayList<String> newTabList = new ArrayList<>();
      newTabList.add(newTabName);
      String[] newPathArray = {generatedPath};
      AppManager.initInstallation(apname, newTabList, newPathArray);
      Util.setCookieSession("newSheet", bundle.getString("autoCreatedSheet"), response);
  }
  
  //redirect
  //  if installed, go to one of the installed app
  if(ifInstall && installed.size()>0){
    String url=installed.get(0);
    
      out.write("<script>location='/");
      out.print(apname);
      out.print(url);
      out.write("';</script>");

  }
  //  if not installed, go to how to build your own form
  else{
    
      out.write("<script>localStorage.setItem('chapter','001b');location='/");
      out.print(apname+generatedPath);
      out.write("';</script>");

  }

